import{_ as e,o as s,c as t,ag as n}from"./chunks/framework.BDReElpY.js";const u=JSON.parse('{"title":"Standard Library","description":"","frontmatter":{},"headers":[],"relativePath":"guide/stdlib.md","filePath":"guide/stdlib.md"}'),l={name:"guide/stdlib.md"};function i(o,a,p,r,d,c){return s(),t("div",null,[...a[0]||(a[0]=[n(`<h1 id="standard-library" tabindex="-1">Standard Library <a class="header-anchor" href="#standard-library" aria-label="Permalink to &quot;Standard Library&quot;">​</a></h1><p>Vex provides a focused standard library and a powerful <strong>Prelude</strong> that is available to all programs automatically.</p><h2 id="the-prelude" tabindex="-1">The Prelude <a class="header-anchor" href="#the-prelude" aria-label="Permalink to &quot;The Prelude&quot;">​</a></h2><p>Core types are available everywhere without an <code>import</code> statement. These include:</p><h3 id="collections" tabindex="-1">Collections <a class="header-anchor" href="#collections" aria-label="Permalink to &quot;Collections&quot;">​</a></h3><ul><li><code>Vec&lt;T&gt;</code>: Dynamic heap-allocated array.</li><li><code>Map&lt;K, V&gt;</code>: Hash map (SwissTable implementation).</li><li><code>Set&lt;T&gt;</code>: Hash set (built on top of Map).</li></ul><h3 id="smart-pointers" tabindex="-1">Smart Pointers <a class="header-anchor" href="#smart-pointers" aria-label="Permalink to &quot;Smart Pointers&quot;">​</a></h3><ul><li><code>Box&lt;T&gt;</code>: Revolutionary unified memory management (VUMM). Automatically selects Unique/SharedRc/AtomicArc.</li></ul><h3 id="error-optionality" tabindex="-1">Error &amp; Optionality <a class="header-anchor" href="#error-optionality" aria-label="Permalink to &quot;Error &amp; Optionality&quot;">​</a></h3><ul><li><code>Result&lt;T, E&gt;</code>: For operations that can fail.</li><li><code>Option&lt;T&gt;</code>: For values that may not exist.</li></ul><hr><h2 id="standard-modules" tabindex="-1">Standard Modules <a class="header-anchor" href="#standard-modules" aria-label="Permalink to &quot;Standard Modules&quot;">​</a></h2><p>Modules in <code>std</code> must be explicitly imported.</p><h3 id="std-fs-file-system" tabindex="-1"><code>std.fs</code> (File System) <a class="header-anchor" href="#std-fs-file-system" aria-label="Permalink to &quot;\`std.fs\` (File System)&quot;">​</a></h3><p>Provides basic file and path operations.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>import * as fs from &quot;fs&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>fn example(): i32 {</span></span>
<span class="line"><span>    // Path handling</span></span>
<span class="line"><span>    let path = fs.newPath(&quot;test.txt&quot;)</span></span>
<span class="line"><span>    if !path.exists() {</span></span>
<span class="line"><span>        println(&quot;File not found&quot;)</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    // File I/O</span></span>
<span class="line"><span>    let! file = fs.open(&quot;test.txt&quot;) !&gt; |err| {</span></span>
<span class="line"><span>        println(f&quot;Error: {err.msg}&quot;)</span></span>
<span class="line"><span>        return 1</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    // ... read/write operations</span></span>
<span class="line"><span>    return 0</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="std-math" tabindex="-1"><code>std.math</code> <a class="header-anchor" href="#std-math" aria-label="Permalink to &quot;\`std.math\`&quot;">​</a></h3><p>Comprehensive math constants and functions.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>import * as math from &quot;math&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>let root = math.sqrt(16.0)</span></span>
<span class="line"><span>let pi = math.PI</span></span></code></pre></div><h3 id="std-time" tabindex="-1"><code>std.time</code> <a class="header-anchor" href="#std-time" aria-label="Permalink to &quot;\`std.time\`&quot;">​</a></h3><p>Time and duration utilities.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>import * as time from &quot;time&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>let start = time.Instant.now()</span></span>
<span class="line"><span>// ... do work</span></span>
<span class="line"><span>let elapsed = start.elapsed()</span></span></code></pre></div><hr><h2 id="future-roadmap" tabindex="-1">Future Roadmap <a class="header-anchor" href="#future-roadmap" aria-label="Permalink to &quot;Future Roadmap&quot;">​</a></h2><p>The following modules are currently in development and not yet available in the stable standard library:</p><ul><li><code>std.json</code> / <code>std.toml</code>: Serialization support.</li><li><code>std.net</code>: Networking (TCP/UDP/HTTP).</li><li><code>std.process</code>: Advanced process management.</li></ul><hr><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/docs/guide/memory/vumm">VUMM Memory Model</a> - How Box works</li><li><a href="/docs/guide/error-handling">Error Handling</a> - Using Result and Option</li><li><a href="/docs/guide/ffi">FFI</a> - Interacting with C code</li></ul>`,29)])])}const m=e(l,[["render",i]]);export{u as __pageData,m as default};
